mapper.insert:
/* 데이터마트 등록/수정 datamart.saveDatamart */
INSERT INTO TB_DM (
    DATAMART_ID
    , DM_NM
    , DESCRIPTION
    , DB_TYPE
    , DB_VERSION
    , HOST
    , PORT
    , DB_NM
    , USERNAME
    , PWD_ENC
    , SCH_NM
    , CONN_OPT
    , READONLY_YN
    , IP_WLIST_YN
    , SSL_YN
    , TBL_CNT
    , SORT_ORD
    , USE_YN
    , CREATE_DT
    , MODIFY_DT
) VALUES (
    #{datamartId}
    , #{dmNm, jdbcType=VARCHAR}
    , #{description, jdbcType=VARCHAR}
    , #{dbType, jdbcType=VARCHAR}
    , #{dbVersion, jdbcType=VARCHAR}
    , #{host, jdbcType=VARCHAR}
    , #{port, jdbcType=INTEGER}
    , #{dbNm, jdbcType=VARCHAR}
    , #{username, jdbcType=VARCHAR}
    , #{pwdEnc, jdbcType=VARCHAR}
    , #{schNm, jdbcType=VARCHAR}
    , #{connOpt, jdbcType=VARCHAR}
    , #{readonlyYn, jdbcType=VARCHAR}
    , #{ipWlistYn, jdbcType=VARCHAR}
    , #{sslYn, jdbcType=VARCHAR}
    , #{tblCnt, jdbcType=INTEGER}
    , #{sortOrd, jdbcType=INTEGER}
    , #{useYn, jdbcType=VARCHAR}
    , NOW()
    , NOW()
)
ON DUPLICATE KEY UPDATE
    DM_NM = VALUES(DM_NM)
    , DESCRIPTION = VALUES(DESCRIPTION)
    , DB_TYPE = VALUES(DB_TYPE)
    , DB_VERSION = VALUES(DB_VERSION)
    , HOST = VALUES(HOST)
    , PORT = VALUES(PORT)
    , DB_NM = VALUES(DB_NM)
    , USERNAME = VALUES(USERNAME)
    , PWD_ENC = VALUES(PWD_ENC)
    , SCH_NM = VALUES(SCH_NM)
    , CONN_OPT = VALUES(CONN_OPT)
    , READONLY_YN = VALUES(READONLY_YN)
    , IP_WLIST_YN = VALUES(IP_WLIST_YN)
    , SSL_YN = VALUES(SSL_YN)
    , TBL_CNT = VALUES(TBL_CNT)
    , SORT_ORD = VALUES(SORT_ORD)
    , USE_YN = VALUES(USE_YN)
    , MODIFY_DT = NOW()

mapper.update:
/* 데이터마트 검증일시 업데이트 datamart.updateLastVerifyDt */
UPDATE TB_DM
SET LAST_VERIFY_DT = NOW()
WHERE DATAMART_ID = #{datamartId}

mapper.delete:
/* 데이터마트 삭제 datamart.deleteDatamart */
DELETE FROM TB_DM
WHERE DATAMART_ID = #{datamartId}

mapper.select:
/* 데이터마트 테이블 사용 여부 조회 datamart.selectDmTblUseYn */
SELECT COALESCE(
    (
        SELECT A.USE_YN
        FROM TB_DM_TBL A
        WHERE A.DATAMART_ID = #{datamartId}
        AND A.TBL_ID = #{tblId}
        LIMIT 1
    ),
    'N'
) AS USE_YN

mapper.insert:
/* 메타 관리 > 테이블 저장 datamart.saveMetaTable */
INSERT INTO TB_DM_TBL (
    DATAMART_ID
    , TBL_ID
    , TBL_PHY_NM
    , TBL_KOR_NM
    , TBL_DESC
    , TBL_CATG
    , COL_CNT
    , AI_HINT
    , SORT_ORD
    , USE_YN
    , CREATE_DT
    , MODIFY_DT
)
VALUES

(
    #{datamartId}
    , #{item.id}
    , #{item.physicalNm}
    , #{item.logicalNm}
    , #{item.tableDescKo}
    , #{item.usageTy}
    , #{item.colCnt}
    , NULL
    , (#{idx} + 1)
    , #{item.useYn}
    , NOW()
    , NOW()
)

ON DUPLICATE KEY UPDATE
    SORT_ORD = VALUES(SORT_ORD)
    , USE_YN = VALUES(USE_YN)
    , MODIFY_DT = NOW()

mapper.delete:
/* 메타 관리 > 컬럼 저장 전 삭제 datamart.deleteDmColByDatamartId */
DELETE FROM TB_DM_COL
WHERE DATAMART_ID = #{datamartId}

mapper.insert:
/* 메타 관리 > 컬럼 일괄 등록 datamart.insertDmColBatch */
INSERT INTO TB_DM_COL (
    DATAMART_ID
    , TBL_ID
    , COL_ID
    , COL_PHY_NM
    , COL_KOR_NM
    , COL_DESC
    , DATA_TYPE
    , DATA_LEN
    , PK_YN
    , FK_YN
    , NULLABLE_YN
    , HAS_CODE_YN
    , AI_HINT
    , SORT_ORD
    , USE_YN
    , CREATE_DT
    , MODIFY_DT
)
VALUES


(
    #{datamartId}
    , #{table.id}
    , #{col.colId}
    , #{col.colPhyNm}
    , #{col.colKorNm}
    , #{col.colDesc}
    , #{col.dataType}
    , #{col.dataLen}
    , #{col.pkYn}
    , #{col.fkYn}
    , #{col.nullableYn}
    , #{col.hasCodeYn}
    , #{col.aiHint}
    , #{col.sortOrd}
    , #{col.useYn}
    , NOW()
    , NOW()
)
